import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Page Settings","description":"","frontmatter":{},"headers":[],"relativePath":"my/Page/page-settings.md","filePath":"my/Page/page-settings.md","lastUpdated":1781962217000}'),o={name:"my/Page/page-settings.md"};function n(i,t,l,g,s,c){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="page-settings" tabindex="-1">Page Settings <a class="header-anchor" href="#page-settings" aria-label="Permalink to &quot;Page Settings&quot;">​</a></h1><p>Page settings က site display, upload page defaults, background images, admin panel appearance တို့ကိုထိန်းချုပ်ပါတယ်။</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Site title</td><td>browser tab မှာပြတဲ့ title။</td></tr><tr><td>Site icon</td><td>browser tab မှာပြတဲ့ icon သေး။</td></tr><tr><td>ImgBed name</td><td>frontend pages မှာပြတဲ့အမည်။</td></tr><tr><td>ImgBed logo</td><td>frontend pages မှာပြတဲ့ logo image။</td></tr><tr><td>Logo link</td><td>logo သို့မဟုတ် avatar နှိပ်တဲ့အခါဖွင့်မယ့် URL။</td></tr><tr><td>Background switch interval</td><td>backgrounds အများအပြားအတွက် rotation interval, milliseconds ဖြင့်။ <code>60000</code> ဆို 60 seconds။</td></tr><tr><td>Background opacity</td><td>background image opacity ကို <code>0</code> မှ <code>1</code> အထိသတ်မှတ်သည်။ တန်ဖိုးနည်းလျှင်ပိုဖျော့သည်။</td></tr><tr><td>Default URL prefix</td><td>image links generate လုပ်တဲ့အခါသုံးတဲ့ prefix။ ဗလာဆို current site domain ကိုသုံးသည်။</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Announcement</td><td>upload page အပေါ်ပိုင်းမှာပြတဲ့ announcement။ HTML support လုပ်သည်။</td></tr><tr><td>Default upload channel</td><td>upload page မှာ default selected ဖြစ်တဲ့ upload channel။ Smart Dispatch ကိုလည်းရွေးနိုင်သည်။</td></tr><tr><td>Default upload directory</td><td>default upload directory၊ ဥပမာ <code>/user/</code>။ ဗလာ သို့မဟုတ် <code>/</code> ဆို root။</td></tr><tr><td>Default naming method</td><td>upload ပြီးနောက် default filename generation strategy။ အောက်မှာကြည့်ပါ။</td></tr><tr><td>Convert to WebP by default</td><td>upload မလုပ်ခင် images ကို WebP ပြောင်းသည်။</td></tr><tr><td>Enable compression by default</td><td>upload မလုပ်ခင် browser ထဲ locally images compress လုပ်သည်။</td></tr><tr><td>Default compression threshold</td><td>image က ဒီ size ကျော်လျှင် automatically compress လုပ်သည်၊ MB ဖြင့်။</td></tr><tr><td>Default target size</td><td>compression ပြီးနောက် target file size, MB ဖြင့်။</td></tr><tr><td>Login page background</td><td>user login page အတွက် background image။</td></tr><tr><td>Upload page background</td><td>upload page အတွက် background image။</td></tr><tr><td>Footer portal link</td><td>footer portal button နှိပ်လျှင်ဖွင့်မယ့် URL။</td></tr><tr><td>Hide footer</td><td>enabled ဖြစ်လျှင် frontend footer ကိုဖျောက်သည်။</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Admin login background</td><td>admin login page အတွက် background image။</td></tr><tr><td>Admin background</td><td>admin pages အတွက် background image။ image URL တစ်ခု သို့မဟုတ် multiple URLs သုံးနိုင်သည်။</td></tr><tr><td>Image loading mode</td><td>admin file list အတွက် preview loading mode။ Original က original images load လုပ်သည်။ Smart loading က public images အတွက် thumbnails ကိုဦးစားပေးပြီး restricted images အတွက် originals ကိုဦးစားပေးသည်။</td></tr><tr><td>Thumbnail source</td><td>thumbnails ဖန်တီးသည့် service: wsrv.nl, Cloudflare Image Resizing, WordPress Photon။ Cloudflare Image Resizing ကိုရွေးမယ်ဆိုရင် Cloudflare ထဲမှာအရင် enable လုပ်ထားရမယ်။</td></tr><tr><td>Live2D widget</td><td>admin panel မှာ Live2D character ပြသည်။</td></tr><tr><td>Firework click effect</td><td>page နှိပ်တဲ့အခါ firework effect ပြသည်။</td></tr><tr><td>Star cursor trail</td><td>mouse ရွှေ့တဲ့အခါ star trail ပြသည်။</td></tr></tbody></table><h2 id="background-image-formats" tabindex="-1">Background Image Formats <a class="header-anchor" href="#background-image-formats" aria-label="Permalink to &quot;Background Image Formats&quot;">​</a></h2><p>Login page background, upload page background, admin login background တို့က ဒီ formats ကို support လုပ်ပါတယ်:</p><table tabindex="0"><thead><tr><th>Value</th><th>Effect</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Bing wallpaper rotation သုံးသည်။</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>images အများအပြား rotate လုပ်သည်။</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>single background image သုံးသည်။</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>random image API link သုံးသည်။ Other Settings မှာ ကိုယ်ပိုင် Random Image API configure လုပ်ပြီး generated random image link ကို single-background entry အဖြစ် paste လုပ်နိုင်သည်။</td></tr></tbody></table><p>admin background က image URLs support လုပ်ပါတယ်။ page prompt အတိုင်း URLs အများအပြားကို English commas နဲ့ခွဲနိုင်ပါတယ်။ ဗလာဆို default background သုံးပါမယ်။</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>time-random prefix + original filename၊ ဥပမာ <code>1760000000000_cat.png</code>။</td></tr><tr><td>Prefix only</td><td>time-random prefix နဲ့ extension ပဲ၊ ဥပမာ <code>1760000000000.png</code>။</td></tr><tr><td>Original name only</td><td>original filename ကိုထားသည်၊ ဥပမာ <code>cat.png</code>။ duplicate ဖြစ်လျှင် ImgBed က <code>(1)</code>, <code>(2)</code> စသဖြင့်ထည့်သည်။</td></tr><tr><td>Short link</td><td>8-character short ID နဲ့ extension သုံးသည်၊ ဥပမာ <code>a1b2c3d4.png</code>။</td></tr></tbody></table>',14)])])}const p=e(o,[["render",n]]);export{u as __pageData,p as default};
